module cortex_m0lite #(
    parameter integer XLEN = 16
) (
    input  logic             clk,
    input  logic             rst_n,
    input  logic             fetch_en,
    input  logic             step_en,
    input  logic             flush,
    input  logic [XLEN-1:0]  instr_data,
    output logic [XLEN-1:0]  pc,
    output logic             busy,
    output logic             retire
);

    // Architectural state owned by timer_core per SSOT function_model.
    logic [XLEN-1:0] pc_q;
    logic            busy_q;
    logic            retire_q;

    // latency=1 contract: accept and compute next visible state on this edge.
    logic            accept_txn;
    logic [XLEN-1:0] pc_next;
    logic            busy_next;
    logic            retire_next;

    assign accept_txn = fetch_en | flush | step_en | retire_q;

    // SSOT FM_TICK output/state expressions.
    assign pc_next = flush ? {XLEN{1'b0}} :
                     (fetch_en ? instr_data :
                     ((step_en && busy_q && (pc_q > {XLEN{1'b0}})) ? (pc_q - {{(XLEN-1){1'b0}},1'b1}) : pc_q));

    assign busy_next = flush ? 1'b0 :
                       (fetch_en ? (instr_data > {XLEN{1'b0}}) :
                       ((step_en && busy_q && (pc_q <= {{(XLEN-1){1'b0}},1'b1})) ? 1'b0 : busy_q));

    assign retire_next = flush ? 1'b0 :
                         (fetch_en ? 1'b0 :
                         ((step_en && busy_q && (pc_q == {{(XLEN-1){1'b0}},1'b1})) ? 1'b1 : 1'b0));

    // Reset/flush invariant: pc=0, busy=0, retire=0.
    // Updates occur once per accepted FM_TICK transaction.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            pc_q     <= {XLEN{1'b0}};
            busy_q   <= 1'b0;
            retire_q <= 1'b0;
        end else if (accept_txn) begin
            pc_q     <= pc_next;
            busy_q   <= busy_next;
            retire_q <= retire_next;
        end
    end

    // Observable outputs are direct views of architectural state.
    assign pc     = pc_q;
    assign busy   = busy_q;
    assign retire = retire_q;

endmodule

